// ============================================================
// pages/AdminLogin.jsx — Admin Login Page
// ============================================================
// Separate login page for admin users.
// On success: stores admin JWT, redirects to /admin/dashboard
// ============================================================

import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { authAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/auth.css";

function AdminLogin() {
  const navigate  = useNavigate();
  const { login, isAuthenticated, role } = useAuth();

  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [error,    setError]    = useState("");
  const [loading,  setLoading]  = useState(false);

  useEffect(() => {
    if (isAuthenticated && role === "admin") {
      navigate("/admin/dashboard", { replace: true });
    }
  }, [isAuthenticated, role, navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (!email || !password) { setError("Please enter email and password"); return; }

    setLoading(true);
    try {
      // Call POST /api/auth/admin/login
      const res = await authAPI.adminLogin(email, password);
      const { access_token, role } = res.data;

      // Save admin token (role = "admin")
      login({ email }, access_token, role);
      navigate("/admin/dashboard");
    } catch (err) {
      setError(err.response?.data?.detail || "Invalid admin credentials");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-logo">
          <div className="brand-name" style={{ color: "#DC2626" }}>PayOnboard</div>
          <div className="brand-tagline">Admin Panel</div>
        </div>

        <h1 className="auth-title">Admin Login</h1>
        <p className="auth-subtitle">Restricted access — authorized personnel only</p>

        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit} noValidate>
          <div className="form-group">
            <label className="form-label">Admin Email</label>
            <input
              className="form-input"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="admin@company.com"
            />
          </div>
          <div className="form-group">
            <label className="form-label">Password</label>
            <input
              className="form-input"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Admin password"
            />
          </div>
          <button className="btn-primary" type="submit" disabled={loading}
            style={{ background: loading ? undefined : "#DC2626" }}>
            {loading ? "Logging In..." : "Admin Sign In"}
          </button>
        </form>

        <p className="auth-footer">
          <Link to="/login">← Back to Merchant Login</Link>
        </p>
      </div>
    </div>
  );
}

export default AdminLogin;
